     1→/**
     2→ * Form Responses Page
     3→ * View and analyze form responses with table view and CSV export
     4→ */
     5→
     6→import { useEffect, useState, useMemo } from 'react';
     7→import { useParams, useNavigate } from 'react-router-dom';
     8→import { StoreErrorBoundary } from '../components/StoreErrorBoundary';
     9→import { useFormsStore } from '../stores/useFormsStore';
    10→import { exportFormResponsesToCSV } from '../utils/formExport';
    11→import { calculateFormAnalytics } from '../services/formAnalytics';
    12→import { ArrowLeft, Download, Trash2, Plus, AlertTriangle, BarChart3 } from 'lucide-react';
    13→import { BarChart, Bar, PieChart, Pie, Cell, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
    14→
    15→export default function FormResponses() {
    16→  const { id } = useParams<{ id: string }>();
    17→  const navigate = useNavigate();
    18→
    19→  const getForm = useFormsStore((s) => s.getForm);
    20→  const getResponses = useFormsStore((s) => s.getResponses);
    21→  const deleteResponse = useFormsStore((s) => s.deleteResponse);
    22→  const clearFormResponses = useFormsStore((s) => s.clearFormResponses);
    23→
    24→  const [form, setForm] = useState(id ? getForm(id) : null);
    25→  const [responses, setResponses] = useState(id ? getResponses(id) : []);
    26→  const [activeTab, setActiveTab] = useState<'responses' | 'analytics'>('responses');
    27→
    28→  useEffect(() => {
    29→    if (!id) {
    30→      navigate('/forms');
    31→      return;
    32→    }
    33→
    34→    const foundForm = getForm(id);
    35→    if (!foundForm) {
    36→      navigate('/forms');
    37→      return;
    38→    }
    39→
    40→    setForm(foundForm);
    41→    setResponses(getResponses(id));
    42→  }, [id, getForm, getResponses, navigate]);
    43→
    44→  if (!form || !id) return null;
    45→
    46→  const handleExport = () => {
    47→    if (responses.length === 0) {
    48→      alert('No responses to export');
    49→      return;
    50→    }
    51→    exportFormResponsesToCSV(form, responses);
    52→  };
    53→
    54→  const handleDeleteResponse = (responseId: string) => {
    55→    if (confirm('Delete this response?')) {
    56→      deleteResponse(responseId);
    57→      setResponses(getResponses(id));
    58→    }
    59→  };
    60→
    61→  const handleClearAll = () => {
    62→    if (confirm(`Delete all ${responses.length} responses? This cannot be undone.`)) {
    63→      clearFormResponses(id);
    64→      setResponses([]);
    65→    }
    66→  };
    67→
    68→  // Sort fields by order for consistent column display
    69→  const sortedFields = [...form.fields].sort((a, b) => a.order - b.order);
    70→
    71→  // Sort responses by most recent first
    72→  const sortedResponses = [...responses].sort(
    73→    (a, b) => new Date(b.submittedAt).getTime() - new Date(a.submittedAt).getTime()
    74→  );
    75→
    76→  // Calculate analytics
    77→  const analytics = useMemo(() => {
    78→    if (!form || responses.length === 0) return null;
    79→    return calculateFormAnalytics(form, responses);
    80→  }, [form, responses]);
    81→
    82→  // Chart colors (using semantic tokens)
    83→  const CHART_COLORS = ['#FF006E', '#8338EC', '#3A86FF', '#06FFA5', '#FFBE0B'];
    84→
    85→  return (
    86→    <StoreErrorBoundary storeName="forms">
    87→      <div className="flex flex-col h-screen bg-background-light dark:bg-background-dark">
    88→        {/* Header */}
    89→        <header className="flex items-center justify-between px-4 py-3 border-b border-border-light dark:border-border-dark bg-surface-light dark:bg-surface-dark">
    90→          <div className="flex items-center gap-3">
    91→            <button
    92→              onClick={() => navigate('/forms')}
    93→              className="p-2 hover:bg-surface-hover-light dark:hover:bg-surface-hover-dark rounded-lg transition-colors"
    94→              aria-label="Back to forms"
    95→            >
    96→              <ArrowLeft className="w-5 h-5" />
    97→            </button>
    98→            <div>
    99→              <h1 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">
   100→                {form.title} - Responses
   101→              </h1>
   102→              <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
   103→                {responses.length} {responses.length === 1 ? 'response' : 'responses'}
   104→              </p>
   105→            </div>
   106→          </div>
   107→
   108→          <div className="flex items-center gap-2">
   109→            <button
   110→              onClick={() => navigate(`/forms/${id}/fill`)}
   111→              className="flex items-center gap-2 px-4 py-2 bg-surface-hover-light dark:bg-surface-hover-dark rounded-lg hover:bg-border-light dark:hover:bg-border-dark"
   112→            >
   113→              <Plus className="w-4 h-4" />
   114→              New Response
   115→            </button>
   116→            {responses.length > 0 && (
   117→              <>
   118→                <button
   119→                  onClick={handleExport}
   120→                  className="flex items-center gap-2 px-4 py-2 bg-primary-light dark:bg-primary-dark text-white rounded-lg hover:opacity-90"
   121→                >
   122→                  <Download className="w-4 h-4" />
   123→                  Export CSV
   124→                </button>
   125→                <button
   126→                  onClick={handleClearAll}
   127→                  className="flex items-center gap-2 px-4 py-2 bg-red-500/10 text-red-500 rounded-lg hover:bg-red-500/20"
   128→                >
   129→                  <Trash2 className="w-4 h-4" />
   130→                  Clear All
   131→                </button>
   132→              </>
   133→            )}
   134→          </div>
   135→        </header>
   136→
   137→        {/* Tabs */}
   138→        <div className="border-b border-border-light dark:border-border-dark bg-surface-light dark:bg-surface-dark">
   139→          <div className="flex gap-1 px-4">
   140→            <button
   141→              onClick={() => setActiveTab('responses')}
   142→              className={`px-4 py-2 font-medium transition-colors border-b-2 ${
   143→                activeTab === 'responses'
   144→                  ? 'border-primary-light dark:border-primary-dark text-primary-light dark:text-primary-dark'
   145→                  : 'border-transparent text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
   146→              }`}
   147→            >
   148→              Responses
   149→            </button>
   150→            <button
   151→              onClick={() => setActiveTab('analytics')}
   152→              className={`flex items-center gap-2 px-4 py-2 font-medium transition-colors border-b-2 ${
   153→                activeTab === 'analytics'
   154→                  ? 'border-primary-light dark:border-primary-dark text-primary-light dark:text-primary-dark'
   155→                  : 'border-transparent text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
   156→              }`}
   157→            >
   158→              <BarChart3 className="w-4 h-4" />
   159→              Analytics
   160→            </button>
   161→          </div>
   162→        </div>
   163→
   164→        {/* Content */}
   165→        <div className="flex-1 overflow-auto p-6">
   166→          {activeTab === 'responses' && (
   167→            <>
   168→              {responses.length === 0 ? (
   169→            <div className="flex flex-col items-center justify-center h-full text-center">
   170→              <div className="w-24 h-24 mb-4 rounded-full bg-surface-light dark:bg-surface-dark flex items-center justify-center">
   171→                <Plus className="w-12 h-12 text-text-light-tertiary dark:text-text-dark-tertiary" />
   172→              </div>
   173→              <h2 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary mb-2">
   174→                No responses yet
   175→              </h2>
   176→              <p className="text-text-light-secondary dark:text-text-dark-secondary mb-6 max-w-md">
   177→                Start collecting data by filling out the form
   178→              </p>
   179→              <button
   180→                onClick={() => navigate(`/forms/${id}/fill`)}
   181→                className="flex items-center gap-2 px-6 py-3 bg-primary-light dark:bg-primary-dark text-white rounded-lg hover:opacity-90"
   182→              >
   183→                <Plus className="w-5 h-5" />
   184→                Fill Form
   185→              </button>
   186→            </div>
   187→          ) : (
   188→            <div className="space-y-4">
   189→              {sortedResponses.map((response) => (
   190→                <div
   191→                  key={response.id}
   192→                  className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-4"
   193→                >
   194→                  {/* Response Header */}
   195→                  <div className="flex items-center justify-between mb-4 pb-3 border-b border-border-light dark:border-border-dark">
   196→                    <div className="flex items-center gap-3">
   197→                      <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
   198→                        Submitted: {new Date(response.submittedAt).toLocaleString()}
   199→                      </div>
   200→                      {response.isSpam && (
   201→                        <div
