   339→              <p className="text-text-light-secondary dark:text-text-dark-secondary mb-2">
   340→                No notes match your filters
   341→              </p>
   342→              <p className="text-sm text-text-light-tertiary dark:text-text-dark-tertiary">
   343→                Try adjusting your search or showing orphan notes
   344→              </p>
   345→            </div>
   346→          </div>
   347→        ) : (
   348→          <div className="flex-1 overflow-hidden">
   349→            <GraphCanvas
   350→              data={graphData}
   351→              onNodeClick={handleNodeClick}
   352→              onNodeDoubleClick={handleNodeDoubleClick}
   353→              focusNodeId={focusNodeId}
   354→              searchResult={searchResult}
   355→              showLinkStrength={showLinkStrength}
   356→              orphanIds={orphanIds}
   357→            />
   358→          </div>
   359→        )}
   360→
   361→        {/* Legend */}
   362→        <div className="flex flex-col gap-2">
   363→          <div className="flex items-center gap-6 text-xs text-text-light-tertiary dark:text-text-dark-tertiary flex-wrap">
   364→            <div className="flex items-center gap-2">
   365→              <div className="w-3 h-3 rounded-full bg-[var(--accent-cyan)]" />
   366→              <span>Notes</span>
   367→            </div>
   368→            <div className="flex items-center gap-2">
   369→              <div className="w-3 h-3 rounded-full bg-[var(--accent-magenta)]" />
   370→              <span>Tags</span>
   371→            </div>
   372→            <div className="flex items-center gap-2">
   373→              <div className="w-3 h-3 rounded-full bg-[var(--accent-magenta)] border-2 border-orange-500" />
   374→              <span>Orphans</span>
   375→            </div>
   376→            <div className="flex items-center gap-2">
   377→              <div className="w-8 h-0.5 bg-[var(--accent-cyan)]" />
   378→              <span>Backlinks</span>
   379→            </div>
   380→            <div className="flex items-center gap-2">
   381→              <div className="w-8 h-0.5 bg-[var(--border-light)] dark:bg-[var(--border-dark)]" />
   382→              <span>Tag connections</span>
   383→            </div>
   384→          </div>
   385→
   386→          {/* P2: Link Strength Legend */}
   387→          <LinkStrengthLegend enabled={showLinkStrength} />
   388→
   389→          {/* P1: Color Groups Legend */}
   390→          {colorBy !== 'none' && colorGroups.size > 0 && (
   391→            <div className="flex items-center gap-4 text-xs text-text-light-tertiary dark:text-text-dark-tertiary flex-wrap">
   392→              <span className="font-medium">{colorBy === 'folder' ? 'Folders:' : 'Tags:'}</span>
   393→              {Array.from(colorGroups.entries()).map(([name, { color, count }]) => (
   394→                <div key={name} className="flex items-center gap-1.5">
   395→                  <div className="w-3 h-3 rounded-full" style={{ backgroundColor: color }} />
   396→                  <span>{name === 'root' ? 'Root' : name}</span>
   397→                  <span className="opacity-60">({count})</span>
   398→                </div>
   399→              ))}
   400→            </div>
   401→          )}
   402→        </div>
   403→
   404→        {/* Instructions */}
   405→        <div className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary">
   406→          <span className="font-medium">Tip:</span> Drag nodes to reposition · Scroll to zoom · Click to focus · Double-click to open
   407→        </div>
   408→        </div>
   409→
   410→        {/* P2: Orphan Panel (Sidebar) */}
   411→        {showOrphanPanel && (
