/**
 * Form Filler Page
 * Fill out a form and submit responses
 */

import { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { StoreErrorBoundary } from '../components/StoreErrorBoundary';
import { useFormsStore } from '../stores/useFormsStore';
import { FormRenderer } from '../components/FormRenderer/FormRenderer';
import { ArrowLeft, Check } from 'lucide-react';

export default function FormFiller() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();

  const getForm = useFormsStore((s) => s.getForm);
  const submitResponse = useFormsStore((s) => s.submitResponse);

  const [form, setForm] = useState(id ? getForm(id) : null);
  const [submitted, setSubmitted] = useState(false);

  useEffect(() => {
    if (!id) {
      navigate('/forms');
      return;
    }

    const foundForm = getForm(id);
    if (!foundForm) {
      navigate('/forms');
      return;
    }

    setForm(foundForm);
  }, [id, getForm, navigate]);

  if (!form || !id) return null;

  const handleSubmit = (
    answers: Record<string, any>,
    metadata?: { isSpam?: boolean; submissionTimeSeconds?: number }
  ) => {
    submitResponse(id, answers, metadata);
    setSubmitted(true);
  };

  const handleFillAnother = () => {
    setSubmitted(false);
    // Optionally reset form by remounting FormRenderer
    window.location.reload();
  };

  if (submitted) {
    return (
      <StoreErrorBoundary storeName="forms">
        <div className="flex flex-col h-screen bg-background-light dark:bg-background-dark">
          <div className="flex-1 flex items-center justify-center">
            <div className="text-center max-w-md p-8">
              <div className="w-16 h-16 bg-green-500/10 rounded-full flex items-center justify-center mx-auto mb-4">
                <Check className="w-8 h-8 text-green-500" />
              </div>
              <h2 className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary mb-2">
                Response Submitted!
              </h2>
              <p className="text-text-light-secondary dark:text-text-dark-secondary mb-6">
                Thank you for completing the form.
              </p>
              <div className="flex flex-col sm:flex-row gap-3 justify-center">
                {form.settings.allowMultipleSubmissions && (
                  <button
                    onClick={handleFillAnother}
                    className="px-6 py-3 bg-primary-light dark:bg-primary-dark text-white rounded-lg hover:opacity-90"
                  >
                    Fill Another Response
                  </button>
                )}
                <button
                  onClick={() => navigate('/forms')}
                  className="px-6 py-3 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg hover:bg-surface-hover-light dark:hover:bg-surface-hover-dark"
                >
                  Back to Forms
                </button>
              </div>
            </div>
          </div>
        </div>
      </StoreErrorBoundary>
    );
  }

  return (
    <StoreErrorBoundary storeName="forms">
      <div className="flex flex-col min-h-screen bg-background-light dark:bg-background-dark">
        {/* Header */}
        <header className="flex items-center justify-between px-4 py-3 border-b border-border-light dark:border-border-dark bg-surface-light dark:bg-surface-dark sticky top-0 z-10">
          <div className="flex items-center gap-3">
            <button
              onClick={() => navigate('/forms')}
              className="p-2 hover:bg-surface-hover-light dark:hover:bg-surface-hover-dark rounded-lg transition-colors"
              aria-label="Back to forms"
            >
              <ArrowLeft className="w-5 h-5" />
            </button>
            <div>
              <h1 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">
                {form.title}
              </h1>
              {form.description && (
                <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                  {form.description}
                </p>
              )}
            </div>
          </div>
        </header>

        {/* Form Content */}
        <div className="flex-1 p-6">
          <div className="max-w-3xl mx-auto">
            {form.fields.length === 0 ? (
              <div className="text-center py-12">
                <p className="text-text-light-secondary dark:text-text-dark-secondary">
                  This form has no fields yet.
                </p>
                <button
                  onClick={() => navigate(`/forms/${id}/edit`)}
                  className="mt-4 px-4 py-2 bg-primary-light dark:bg-primary-dark text-white rounded-lg hover:opacity-90"
                >
                  Edit Form
                </button>
              </div>
            ) : (
              <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-6">
                <FormRenderer form={form} onSubmit={handleSubmit} />
              </div>
            )}
          </div>
        </div>
      </div>
    </StoreErrorBoundary>
  );
}

/**
 * Form Responses Page
 * View and analyze form responses with table view and CSV export
 */

import { useEffect, useState, useMemo } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { StoreErrorBoundary } from '../components/StoreErrorBoundary';
import { useFormsStore } from '../stores/useFormsStore';
import { exportFormResponsesToCSV } from '../utils/formExport';
import { calculateFormAnalytics } from '../services/formAnalytics';
import { ArrowLeft, Download, Trash2, Plus, AlertTriangle, BarChart3 } from 'lucide-react';
import { BarChart, Bar, PieChart, Pie, Cell, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

export default function FormResponses() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();

  const getForm = useFormsStore((s) => s.getForm);
  const getResponses = useFormsStore((s) => s.getResponses);
  const deleteResponse = useFormsStore((s) => s.deleteResponse);
  const clearFormResponses = useFormsStore((s) => s.clearFormResponses);

  const [form, setForm] = useState(id ? getForm(id) : null);
  const [responses, setResponses] = useState(id ? getResponses(id) : []);
  const [activeTab, setActiveTab] = useState<'responses' | 'analytics'>('responses');

  useEffect(() => {
    if (!id) {
      navigate('/forms');
      return;
    }

    const foundForm = getForm(id);
    if (!foundForm) {
      navigate('/forms');
      return;
    }

    setForm(foundForm);
    setResponses(getResponses(id));
  }, [id, getForm, getResponses, navigate]);

  if (!form || !id) return null;

  const handleExport = () => {
    if (responses.length === 0) {
      alert('No responses to export');
      return;
    }
    exportFormResponsesToCSV(form, responses);
  };

  const handleDeleteResponse = (responseId: string) => {
    if (confirm('Delete this response?')) {
      deleteResponse(responseId);
      setResponses(getResponses(id));
    }
  };

  const handleClearAll = () => {
    if (confirm(`Delete all ${responses.length} responses? This cannot be undone.`)) {
      clearFormResponses(id);
      setResponses([]);
    }
  };

  // Sort fields by order for consistent column display
  const sortedFields = [...form.fields].sort((a, b) => a.order - b.order);

  // Sort responses by most recent first
  const sortedResponses = [...responses].sort(
    (a, b) => new Date(b.submittedAt).getTime() - new Date(a.submittedAt).getTime()
  );

  // Calculate analytics
  const analytics = useMemo(() => {
    if (!form || responses.length === 0) return null;
    return calculateFormAnalytics(form, responses);
  }, [form, responses]);

  // Chart colors (using semantic tokens)
  const CHART_COLORS = ['#FF006E', '#8338EC', '#3A86FF', '#06FFA5', '#FFBE0B'];

  return (
    <StoreErrorBoundary storeName="forms">
      <div className="flex flex-col h-screen bg-background-light dark:bg-background-dark">
        {/* Header */}
        <header className="flex items-center justify-between px-4 py-3 border-b border-border-light dark:border-border-dark bg-surface-light dark:bg-surface-dark">
          <div className="flex items-center gap-3">
            <button
              onClick={() => navigate('/forms')}
              className="p-2 hover:bg-surface-hover-light dark:hover:bg-surface-hover-dark rounded-lg transition-colors"
              aria-label="Back to forms"
            >
              <ArrowLeft className="w-5 h-5" />
            </button>
            <div>
              <h1 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">
                {form.title} - Responses
              </h1>
              <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                {responses.length} {responses.length === 1 ? 'response' : 'responses'}
              </p>
