            <button
              onClick={() => navigate(`/forms/${id}/fill`)}
              className="flex items-center gap-2 px-4 py-2 bg-surface-hover-light dark:bg-surface-hover-dark rounded-lg hover:bg-border-light dark:hover:bg-border-dark"
